class SecureSessionManager:
    def __init__(self, redis_client, prefix='session:'):
        self.redis = redis_client
        self.prefix = prefix
    
    def set_session(self, session_id, data, expiry=3600):
        key = f"{self.prefix}{session_id}"
        self.redis.setex(key, expiry, json.dumps(data))
    
    def get_session(self, session_id):
        key = f"{self.prefix}{session_id}"
        data = self.redis.get(key)
        return json.loads(data) if data else None
    
    def delete_session(self, session_id):
        key = f"{self.prefix}{session_id}"
        self.redis.delete(key)
    
    def extend_session(self, session_id, expiry=3600):
        key = f"{self.prefix}{session_id}"
        self.redis.expire(key, expiry)


session_manager = SecureSessionManager(redis_client)


def cache_query(expiry=300, prefix='cache:'):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_key_data = f"{func.__name__}:{str(args)}:{str(sorted(kwargs.items()))}"
            cache_key = f"{prefix}{hashlib.sha256(cache_key_data.encode()).hexdigest()}"
            
            try:
                cached_result = redis_client.get(cache_key)
                if cached_result:
                    return json.loads(cached_result)
            except redis.RedisError as e:
                app.logger.error(f"Cache read error: {str(e)}")
            
            result = func(*args, **kwargs)
            
            try:
                redis_client.setex(cache_key, expiry, json.dumps(result))
            except redis.RedisError as e:
                app.logger.error(f"Cache write error: {str(e)}")
            
            return result
        return wrapper
    return decorator


def invalidate_cache(pattern='cache:*'):
    try:
        keys = redis_client.keys(pattern)
        if keys:
            redis_client.delete(*keys)
    except redis.RedisError as e:
        app.logger.error(f"Cache invalidation error: {str(e)}")


